import React from "react";
import Navbar from 'react-bootstrap/Navbar';
import Nav from 'react-bootstrap/Nav';
import { withRouter } from 'react-router-dom';
import "../styles/header.css";
import "../index.css";

const linkToText = {
  "/aboutMe" : "ABOUT",
  "/reviews" : "REVIEWS", 
  "/portfolio" : "PORTFOLIO", 
  "/contact" : "CONTACT"
};

class Header extends React.Component {

  getLink = (linkName) => {

    return (
      <Nav.Link
        className="header-text"
        href={linkName}
        key={linkName}
      >
        { linkToText[linkName] }
      </Nav.Link>
    );
  }

  render() {
    return (
      <div >

      <Navbar bg="light" expand="md" fixed="top" onSelect="test()">
        <Navbar.Brand href="/">
            <img
                src={require("../images/AR.png")}
                width="50"
                height="45"
            />
        </Navbar.Brand>

        <Navbar.Toggle aria-controls="responsive-navbar-nav" className={styles.navbarToggler} />
        <Navbar.Collapse id="responsive-navbar-nav">
          <Nav className="ml-auto">
            <Link href="/about-us" passHref><ActiveLink>About Us</ActiveLink></Link>
            <Link href="/projects" passHref><ActiveLink>Projects</ActiveLink></Link>
            <Link href="/students" passHref><ActiveLink>Students</ActiveLink></Link>
            <Link href="/nonprofits" passHref><ActiveLink>Nonprofits</ActiveLink></Link>
            <Link href="/contact-us" passHref><ActiveLink>Contact Us</ActiveLink></Link>
            <a target="_blank" href="https://securelb.imodules.com/s/699/bp19/interior.aspx?sid=699&gid=1&sitebuilder=1&pgid=961&cid=2272&bledit=1&dids=623"><ActiveLink>Donate</ActiveLink></a>
          </Nav>
        </Navbar.Collapse>
      </Navbar>

        <Navbar id="site-header" className="header-outer">
            <Navbar.Brand href="/">
            <img
                src={require("../images/AR.png")}
                width="50"
                height="45"
            />
            </Navbar.Brand>
          <Nav>
            <div className="header-content">{ Object.keys(linkToText).map(this.getLink) }</div>
          </Nav>
      </Navbar>
      </div>
    );
  }
}
export default withRouter(Header);
